    57	int nfapi_p7_update_checksum(uint8_t *buffer, uint32_t len) {
    58	  uint32_t checksum = nfapi_calculate_checksum(buffer, len);
    59	  uint8_t *p_write = &buffer[8];
    60	  return (push32(checksum, &p_write, buffer + len) > 0 ? 0 : -1);
    61	}
