			NFAPI_TRACE(NFAPI_TRACE_ERROR, "%s failed to allocate value->harq.harq_payload\n", __FUNCTION__);
			return 0;
		}

		if (!pullarray8(ppReadPackedMsg, value->harq.harq_payload,
				(int)((value->harq.harq_bit_len / 8) + 1),
